# =============================================================================
# Turkey EV Infrastructure Analysis — 2027 Forecast & Bottleneck Mapping
# Project: Team-EV-Turkey
# =============================================================================

# ---- 1. Libraries -----------------------------------------------------------
required_pkgs &lt;- c("tidyverse", "scales", "rnaturalearth", "rnaturalearthdata",
                   "sf", "stringi", "leaflet")
for (pkg in required_pkgs) {
  if (!require(pkg, character.only = TRUE)) {
    install.packages(pkg, repos = "[https://cloud.r-project.org](https://cloud.r-project.org)")
    library(pkg, character.only = TRUE)
  }
}

# ---- 2. Load data -----------------------------------------------------------
load("clear_data/tidy_ev_data_FINAL.RData")

# ---- 3. Helper: normalize province names for joining ------------------------
normalize_name &lt;- function(x) {
  x |&gt;
    stri_trans_general("Latin-ASCII") |&gt;
    str_to_lower() |&gt;
    str_replace_all("[^a-z]", "") |&gt;
    str_trim()
}

# ---- 4. Build analysis-ready dataset ----------------------------------------
analysis_ready &lt;- final_df |&gt;
  mutate(
    ev_per_station  = ev_sayisi / istasyon_sayisi,
    ev_market_share = (ev_sayisi / otomobil_sayisi) * 100,
    date            = as.Date(paste0(str_replace(tarih, "_", "-"), "-01")),
    province_key    = normalize_name(sehir)
  ) |&gt;
  arrange(sehir, date)

# ---- 4.5 Hotfix: source-data anomaly in November 2025 -----------------------
analysis_ready &lt;- analysis_ready |&gt;
  group_by(sehir) |&gt;
  arrange(date) |&gt;
  mutate(
    ev_sayisi = if_else(
      ev_sayisi &lt; lag(ev_sayisi) * 0.5 & ev_sayisi &lt; lead(ev_sayisi) * 0.5,
      round((lag(ev_sayisi) + lead(ev_sayisi)) / 2),
      ev_sayisi
    )
  ) |&gt;
  ungroup()

# ---- 5. Correlation: EV adoption vs. station investment ---------------------
global_cor &lt;- cor(analysis_ready$ev_sayisi,
                  analysis_ready$istasyon_sayisi,
                  use = "complete.obs")
cat("\n--- EVIDENCE ---\n")



--- EVIDENCE ---


